{"command": "Set-Location "d:\CapsoneProject\Mobile\green-lens-app"
$hooks = @(
  @{ name = "suggest_compact"; cmd = "python .claude/hooks/suggest_compact.py"; stdin = $null },
  @{ name = "observe_pre"; cmd = "python .claude/hooks/observe.py pre"; stdin = '{"tool_name":"Write","cwd":"d:/CapsoneProject/Mobile/green-lens-app","session_id":"test","tool_input":{}}' },
  @{ name = "observe_post"; cmd = "python .claude/hooks/observe.py post"; stdin = '{"tool_name":"Write","cwd":"d:/CapsoneProject/Mobile/green-lens-app","session_id":"test","tool_output":{}}' },
  @{ name = "pre_write_guard"; cmd = "python .claude/hooks/pre_write_guard.py"; stdin = '{"tool_name":"Write","file_path":"package.json"}' },
  @{ name = "plan-context"; cmd = "python .claude/hooks/plan-context.py"; stdin = '{}' },
  @{ name = "pre-compact"; cmd = "python .claude/hooks/pre-compact.py"; stdin = $null },
  @{ name = "session-start"; cmd = "python .claude/hooks/session-start.py"; stdin = $null },
  @{ name = "session-end"; cmd = "python .claude/hooks/session-end.py"; stdin = '{}' }
)
foreach ($h in $hooks) {
  if ($null -ne $h.stdin) {
    $h.stdin | & cmd /c "$($h.cmd) 2>&1"
  } else {
    & cmd /c "$($h.cmd) 2>&1"
  }
  $code = $LASTEXITCODE
  Write-Host "---- $($h.name): exit $code ----"
}
if (Test-Path .claude/hooks/build-check.py) {
  python .claude/hooks/build-check.py 2>&1
  Write-Host "---- build-check: exit $LASTEXITCODE ----"
} else {
  Write-Host "---- build-check: SKIPPED (file missing) ----"
}", "cwd": "", "timeout": 30000}
